  { tag: "V1"; value: TxPayloadV1 };

export const VersionedTxPayload: S.Codec<VersionedTxPayload> = S.lazy(
  (): S.Codec<VersionedTxPayload> =>
    S.indexedTaggedUnion({ V1: [0, TxPayloadV1] as const }),
);

